  /* ---- Waiting For ---- */
  .waiting-for {
    padding-block-start: var(--space-lg);
  }

  .waiting-for h1 {
    margin-block-end: var(--space-lg);
  }

  .waiting-for__error {
    background-color: var(--color-danger-light);
    color: var(--color-danger);
    padding: var(--space-sm) var(--space-md);
    border-radius: var(--radius-md);
    font-size: var(--font-size-sm);
    margin-block-end: var(--space-md);
  }

  /* Add waiting-for form */
  .waiting-for__add {
    margin-block-end: var(--space-lg);
  }

  .waiting-for__add-fields {
    display: flex;
    flex-direction: column;
    gap: var(--space-sm);
  }

  .waiting-for__add-group {
    display: flex;
    flex-direction: column;
    gap: var(--space-xs);
  }

  .waiting-for__add-input {
    inline-size: 100%;
  }

  .waiting-for__add-row {
    display: flex;
    gap: var(--space-sm);
  }

  .waiting-for__person-input {
    flex: 1;
    min-inline-size: 8rem;
  }

  .waiting-for__add-submit {
    flex-shrink: 0;
  }

  /* Waiting-for item list */
  .waiting-for__list {
    display: flex;
    flex-direction: column;
  }

  .waiting-for-item {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: var(--space-sm);
    padding-block: var(--space-sm);
    padding-inline: var(--space-sm);
    border-block-end: 1px solid var(--color-border);
  }

  .waiting-for-item:first-child {
    border-block-start: 1px solid var(--color-border);
  }

  .waiting-for-item__content {
    flex: 1;
    min-inline-size: 0;
    display: flex;
    flex-direction: column;
    gap: var(--space-xs);
  }

  .waiting-for-item__title {
    overflow-wrap: break-word;
  }

  .waiting-for-item__person {
    font-size: var(--font-size-sm);
    color: var(--color-fg-muted);
  }

  .waiting-for-item__date {
    flex-shrink: 0;
    font-size: var(--font-size-xs);
    color: var(--color-fg-subtle);
  }

  .waiting-for-item__edit {
    color: var(--color-fg-muted);
    font-size: var(--font-size-sm);
    text-decoration: none;
    flex-shrink: 0;
  }

  .waiting-for-item__edit:hover {
    color: var(--color-primary);
    text-decoration: underline;
  }

  .waiting-for-item__complete {
    flex-shrink: 0;
  }

  .waiting-for-item__complete-button {
    background: none;
    border: none;
    padding: var(--space-xs);
    cursor: pointer;
    color: var(--color-fg-muted);
    font-size: var(--font-size-sm);
    border-radius: var(--radius-sm);
  }

  .waiting-for-item__complete-button:hover {
    background: none;
    color: var(--color-success);
  }

  .waiting-for-item__delete {
    flex-shrink: 0;
  }

  .waiting-for-item__delete-button {
    background: none;
    border: none;
    padding: var(--space-xs);
    cursor: pointer;
    color: var(--color-fg-muted);
    font-size: var(--font-size-sm);
    border-radius: var(--radius-sm);
  }

  .waiting-for-item__delete-button:hover {
    background: none;
    color: var(--color-danger);
  }

  /* Waiting-for edit form */
  .waiting-for-item__edit-form {
    flex: 1;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--space-sm);
    min-inline-size: 0;
  }

  .waiting-for-item__edit-fields {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: var(--space-xs);
    min-inline-size: 0;
  }

  .waiting-for-item__edit-input {
    inline-size: 100%;
    font-size: var(--font-size-base);
    padding: var(--space-xs) var(--space-sm);
  }

  .waiting-for-item__edit-person-input {
    inline-size: 100%;
    font-size: var(--font-size-sm);
    padding: var(--space-xs) var(--space-sm);
  }

  .waiting-for-item__edit-actions {
    display: flex;
    align-items: center;
    gap: var(--space-xs);
    flex-shrink: 0;
  }

  .waiting-for-item__edit-save {
    font-size: var(--font-size-xs);
    padding: var(--space-xs) var(--space-sm);
    border: none;
    border-radius: var(--radius-sm);
    cursor: pointer;
    flex-shrink: 0;
    background-color: var(--color-primary);
    color: white;
  }

  .waiting-for-item__edit-cancel {
    font-size: var(--font-size-xs);
    color: var(--color-fg-muted);
    text-decoration: none;
    flex-shrink: 0;
  }

  .waiting-for-item__edit-cancel:hover {
    color: var(--color-fg);
    text-decoration: underline;
  }

  /* Waiting-for empty state */
  .waiting-for__empty-state {
    color: var(--color-fg-muted);
    font-size: var(--font-size-sm);
    text-align: center;
    padding-block: var(--space-xl);
  }
}

/* ==========================================================================
   UTILITIES LAYER
   Helper classes. These have the highest layer priority.
   ========================================================================== */

@layer utilities {
  /* Visually hidden -- accessible to screen readers but not visible.
   * Uses the clip technique for reliable hiding.
   * white-space: nowrap prevents content from being announced as
   * multiple separate items by some screen readers. */
  .visually-hidden,
  .sr-only {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    white-space: nowrap;
    border: 0;
  }

  /* Skip link -- visually hidden until focused, then revealed.
   * Keyboard users tab to this first and see it appear at the
   * top of the page. Uses the base template's skip link:
   * <a href="#main-content" class="skip-link">Skip to main content</a> */
  .skip-link {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    white-space: nowrap;
    border: 0;

    &:focus-visible {
      position: fixed;
      inset-block-start: var(--space-sm);
      inset-inline-start: var(--space-sm);
      z-index: 9999;
      inline-size: auto;
      block-size: auto;
      padding: var(--space-sm) var(--space-md);
      margin: 0;
      overflow: visible;
      clip: auto;
      clip-path: none;
      white-space: normal;
      background-color: var(--color-primary);
      color: white;
      font-size: var(--font-size-sm);
      font-weight: var(--font-medium);
      border-radius: var(--radius-md);
      box-shadow: var(--shadow-md);
    }
  }
}
